using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to use this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// Configure services
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddHttpClient();
services.AddSingleton<ResearchNotes>();
var sp = services.BuildServiceProvider();

// Create the LLM-backed chat client
IChatClient chatClient = new OpenAIClient(apiKey).AsChatClient(modelId);

// Wire up tools
var notes = sp.GetRequiredService<ResearchNotes>();
var httpFactory = sp.GetRequiredService<IHttpClientFactory>();

var searchTool = new WebSearchTool(httpFactory);
var noteTool = new NoteTool(notes);

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchWeb),
    AIFunctionFactory.Create(noteTool.SaveNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
};

// Create the research agent with instructions
var agent = new ChatClientAgent(
    chatClient,
    id: "research-agent",
    name: "ResearchAgent",
    instructions: """
        You are a thorough research agent. Follow this process:

        1. SEARCH — Use SearchWeb to find information about the topic.
           Make at least 3 searches with different queries to cover various angles.
        2. NOTE — Use SaveNote to record each important finding with a clear title.
        3. REVIEW — Use GetNotes to review everything you collected.
        4. SUMMARIZE — Write a comprehensive, well-organized summary that synthesizes
           all your findings. Include key facts, context, and any notable details.

        Be thorough but focused. Always attribute information to its source.
        """,
    tools: tools,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>(),
    serviceProvider: sp);

// Prompt the user for a research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine("The agent is searching the web and collecting notes...\n");

// Run the agent with a cancellation token tied to Ctrl+C
using var cts = new CancellationTokenSource();
Console.CancelKeyPress += (_, e) =>
{
    e.Cancel = true;
    cts.Cancel();
};

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic thoroughly and provide a comprehensive summary: {topic}",
    session,
    cancellationToken: cts.Token);

Console.WriteLine("════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("════════════════════════════════════════\n");
Console.WriteLine(response.Text);

if (notes.All.Count > 0)
{
    Console.WriteLine($"\n({notes.All.Count} research note(s) were collected during this session)");
}

