using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>In-memory store for research notes collected by the agent.</summary>
public sealed class ResearchNotes
{
    private readonly List<(string Title, string Content)> _notes = [];

    public void Add(string title, string content) => _notes.Add((title, content));

    public IReadOnlyList<(string Title, string Content)> All => _notes;
}

/// <summary>Web search tool that queries the DuckDuckGo Instant Answer API.</summary>
public sealed class WebSearchTool(IHttpClientFactory httpClientFactory)
{
    [Description("Search the web for information about a topic. Returns summaries and related results.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient();
        client.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var json = await client.GetStringAsync(url, cancellationToken);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Heading", out var heading) &&
                heading.GetString() is { Length: > 0 } h)
            {
                results.Add($"Topic: {h}");
            }

            if (root.TryGetProperty("Abstract", out var abs) &&
                abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = root.TryGetProperty("AbstractSource", out var src)
                    ? src.GetString() : "Unknown";
                results.Add($"[{source}] {abstractText}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(8))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } t)
                    {
                        var firstUrl = topic.TryGetProperty("FirstURL", out var u)
                            ? u.GetString() : null;
                        results.Add(firstUrl is not null ? $"• {t} ({firstUrl})" : $"• {t}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing with more specific terms.";
        }
        catch (HttpRequestException ex)
        {
            return $"Search request failed: {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Note-taking tool the agent uses to record and review findings.</summary>
public sealed class NoteTool(ResearchNotes notes)
{
    [Description("Save a research note to record an important finding.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        notes.Add(title, content);
        return $"Saved note \"{title}\" ({notes.All.Count} total).";
    }

    [Description("Retrieve all saved research notes to review collected findings.")]
    public string GetNotes()
    {
        if (notes.All.Count == 0)
            return "No notes have been saved yet.";

        return string.Join("\n---\n",
            notes.All.Select((n, i) => $"[{i + 1}] {n.Title}\n{n.Content}"));
    }
}

